<td style="vertical-align:top;padding:0;margin:0;border:0;;width:100%">
<pre tabindex="0" style="background-color:#eed;-moz-tab-size:4;-o-tab-size:4;tab-size:4;"><code class="language-java" data-lang="java"><span style="display:flex;"><span><span style="color:#8b008b;font-weight:bold">import</span> <span style="color:#008b45;text-decoration:underline">java.io.*</span>;
</span></span><span style="display:flex;"><span><span style="color:#8b008b;font-weight:bold">import</span> <span style="color:#008b45;text-decoration:underline">java.util.*</span>;
</span></span><span style="display:flex;"><span>
</span></span><span style="display:flex;"><span><span style="color:#228b22">// 类名称必须采用public class Main方式命名
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span><span style="color:#8b008b;font-weight:bold">public</span> <span style="color:#8b008b;font-weight:bold">class</span> <span style="color:#008b45;font-weight:bold">Main</span> {
</span></span><span style="display:flex;"><span>
</span></span><span style="display:flex;"><span>    <span style="color:#8b008b;font-weight:bold">public</span> <span style="color:#8b008b;font-weight:bold">static</span> <span style="color:#00688b;font-weight:bold">void</span> <span style="color:#008b45">main</span>(String[] args) {
</span></span><span style="display:flex;"><span>        Scanner scanner = <span style="color:#8b008b;font-weight:bold">new</span> Scanner(<span style="color:#8b008b;font-weight:bold">new</span> BufferedInputStream(System.<span style="color:#658b00">in</span>)); <span style="color:#228b22">// 更快一点
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span>        <span style="color:#228b22">// Scanner scanner = new Scanner(System.in);
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span>        <span style="color:#00688b;font-weight:bold">int</span> a = scanner.<span style="color:#658b00">nextInt</span>();          <span style="color:#228b22">// 读入数字
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span>        <span style="color:#00688b;font-weight:bold">double</span> b = scanner.<span style="color:#658b00">nextDouble</span>();    <span style="color:#228b22">// 读入浮点数
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span>        String s = scanner.<span style="color:#658b00">next</span>();          <span style="color:#228b22">// 读入字符串
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span>
</span></span><span style="display:flex;"><span>        <span style="color:#228b22">// 判断是否有下一个输入
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span>        scanner.<span style="color:#658b00">hasNextInt</span>();
</span></span><span style="display:flex;"><span>        scanner.<span style="color:#658b00">hasNextDouble</span>();
</span></span><span style="display:flex;"><span>        scanner.<span style="color:#658b00">hasNext</span>();
</span></span><span style="display:flex;"><span>
</span></span><span style="display:flex;"><span>        <span style="color:#228b22">// 输出函数
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span>        System.<span style="color:#658b00">out</span>.<span style="color:#658b00">print</span>(a);
</span></span><span style="display:flex;"><span>        System.<span style="color:#658b00">out</span>.<span style="color:#658b00">println</span>(b);
</span></span><span style="display:flex;"><span>        System.<span style="color:#658b00">out</span>.<span style="color:#658b00">format</span>(<span style="color:#cd5555">&#34;%.2f, %s&#34;</span>, 1.<span style="color:#658b00">0</span> * a / b, s);
</span></span><span style="display:flex;"><span>
</span></span><span style="display:flex;"><span>
</span></span><span style="display:flex;"><span>        <span style="color:#228b22">// example1 : 读入多个整数
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span>        <span style="color:#8b008b;font-weight:bold">while</span>(scanner.<span style="color:#658b00">hasNext</span>()){
</span></span><span style="display:flex;"><span>            <span style="color:#00688b;font-weight:bold">int</span> score = scanner.<span style="color:#658b00">nextInt</span>();
</span></span><span style="display:flex;"><span>        }
</span></span><span style="display:flex;"><span>
</span></span><span style="display:flex;"><span>        <span style="color:#228b22">// example2 : 已知字符串数目，读入多行字符串
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span>        <span style="color:#00688b;font-weight:bold">int</span> num = scanner.<span style="color:#658b00">nextInt</span>();
</span></span><span style="display:flex;"><span>        <span style="color:#8b008b;font-weight:bold">for</span> (<span style="color:#00688b;font-weight:bold">int</span> i = 0; i &lt; num; i++) {
</span></span><span style="display:flex;"><span>            String str = scanner.<span style="color:#658b00">next</span>();
</span></span><span style="display:flex;"><span>        }
</span></span><span style="display:flex;"><span>
</span></span><span style="display:flex;"><span>        <span style="color:#228b22">// example3 : 读取二维数组
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span>        <span style="color:#8b008b;font-weight:bold">while</span>(scanner.<span style="color:#658b00">hasNext</span>()){
</span></span><span style="display:flex;"><span>            <span style="color:#00688b;font-weight:bold">int</span> r = scanner.<span style="color:#658b00">nextInt</span>();
</span></span><span style="display:flex;"><span>            <span style="color:#00688b;font-weight:bold">int</span> c = scanner.<span style="color:#658b00">nextInt</span>();
</span></span><span style="display:flex;"><span>            <span style="color:#00688b;font-weight:bold">int</span>[][] matrix = <span style="color:#8b008b;font-weight:bold">new</span> <span style="color:#00688b;font-weight:bold">int</span>[r][c];
</span></span><span style="display:flex;"><span>            scanner.<span style="color:#658b00">nextLine</span>(); <span style="color:#228b22">// 跳换行符
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span>            <span style="color:#8b008b;font-weight:bold">for</span>(<span style="color:#00688b;font-weight:bold">int</span> i = 0; i &lt; r; i++){
</span></span><span style="display:flex;"><span>                <span style="color:#8b008b;font-weight:bold">for</span>(<span style="color:#00688b;font-weight:bold">int</span> j = 0; j &lt; c; j++){
</span></span><span style="display:flex;"><span>                    matrix[i][j] = scanner.<span style="color:#658b00">nextInt</span>();
</span></span><span style="display:flex;"><span>                }
</span></span><span style="display:flex;"><span>            }
</span></span><span style="display:flex;"><span>        }
</span></span><span style="display:flex;"><span>    }
</span></span><span style="display:flex;"><span>}
</span></span></code></pre></td></tr></table>
</div>
