<pre tabindex="0" style="background-color:#eed;-moz-tab-size:4;-o-tab-size:4;tab-size:4;"><code class="language-java" data-lang="java"><span style="display:flex;"><span><span style="color:#8b008b;font-weight:bold">import</span> <span style="color:#008b45;text-decoration:underline">java.util.Scanner</span>;
</span></span><span style="display:flex;"><span>
</span></span><span style="display:flex;"><span><span style="color:#8b008b;font-weight:bold">public</span> <span style="color:#8b008b;font-weight:bold">class</span> <span style="color:#008b45;font-weight:bold">Main</span> {
</span></span><span style="display:flex;"><span>    <span style="color:#8b008b;font-weight:bold">public</span> <span style="color:#8b008b;font-weight:bold">static</span> <span style="color:#00688b;font-weight:bold">void</span> <span style="color:#008b45">main</span>(String[] args) {
</span></span><span style="display:flex;"><span>        Scanner in = <span style="color:#8b008b;font-weight:bold">new</span> Scanner(System.<span style="color:#658b00">in</span>);
</span></span><span style="display:flex;"><span>        <span style="color:#228b22">// 一行行读
</span></span></span><span style="display:flex;"><span><span style="color:#228b22"></span>        <span style="color:#8b008b;font-weight:bold">while</span>(in.<span style="color:#658b00">hasNextLine</span>()){
</span></span><span style="display:flex;"><span>            String[] temp = in.<span style="color:#658b00">nextLine</span>().<span style="color:#658b00">split</span>(<span style="color:#cd5555">&#34; &#34;</span>);
</span></span><span style="display:flex;"><span>            <span style="color:#00688b;font-weight:bold">int</span> sum = 0;
</span></span><span style="display:flex;"><span>            <span style="color:#8b008b;font-weight:bold">for</span>(<span style="color:#00688b;font-weight:bold">int</span> i = 0; i &lt; temp.<span style="color:#658b00">length</span>; i++){
</span></span><span style="display:flex;"><span>                sum += Integer.<span style="color:#658b00">parseInt</span>(temp[i]);
</span></span><span style="display:flex;"><span>            }
</span></span><span style="display:flex;"><span>            System.<span style="color:#658b00">out</span>.<span style="color:#658b00">println</span>(sum);
</span></span><span style="display:flex;"><span>        }
</span></span><span style="display:flex;"><span>    }
</span></span><span style="display:flex;"><span>}
</span></span></code></pre></td></tr></table>
